CSS='\n:root{--bg:#061015;--panel:rgba(15,24,38,.82);--line:rgba(143,255,219,.23);--text:#fff7ea;--muted:#b8c9d8;--mint:#72ffd1;--aqua:#7be5ff;--gold:#ffe76d;--violet:#a78bfa;--rose:#ff6b9a;--shadow:0 24px 80px rgba(0,0,0,.45)}\n*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;min-height:100vh;background:radial-gradient(circle at 12% 18%,rgba(64,255,203,.18),transparent 30%),radial-gradient(circle at 72% 10%,rgba(255,214,94,.14),transparent 28%),radial-gradient(circle at 75% 80%,rgba(133,96,255,.16),transparent 32%),linear-gradient(120deg,#061016,#0d1226 65%,#06060e);color:var(--text);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;overflow-x:hidden}body:before{content:"";position:fixed;inset:0;pointer-events:none;background-image:linear-gradient(rgba(255,255,255,.035) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.03) 1px,transparent 1px);background-size:34px 34px;mask-image:linear-gradient(to bottom,#000,rgba(0,0,0,.72),transparent);z-index:0}body:after{content:"GOALOS";position:fixed;left:-3vw;bottom:-12vh;font-size:19vw;font-weight:1000;letter-spacing:-.08em;color:rgba(255,255,255,.055);pointer-events:none;z-index:0}.wrap{position:relative;z-index:1;width:min(1220px,92vw);margin:0 auto}.nav{position:sticky;top:18px;z-index:50;margin:18px auto 42px;padding:12px 14px;border:1px solid rgba(255,255,255,.13);border-radius:28px;background:rgba(4,9,18,.83);backdrop-filter:blur(22px);box-shadow:var(--shadow);display:flex;align-items:center;justify-content:space-between;gap:14px}.brand{display:flex;gap:12px;align-items:center;font-weight:950;letter-spacing:.16em;text-transform:uppercase;font-size:12px;color:var(--text);text-decoration:none}.logo{width:38px;height:38px;border-radius:13px;background:radial-gradient(circle at 30% 25%,var(--gold),var(--mint) 38%,#89b7ff 72%,#7c4dff);box-shadow:0 0 34px rgba(114,255,209,.3)}.links{display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end}.links a,.chip,.btn{color:var(--text);text-decoration:none;border:1px solid rgba(255,255,255,.16);background:rgba(255,255,255,.07);border-radius:999px;padding:10px 14px;font-weight:850;font-size:13px;line-height:1;box-shadow:inset 0 1px rgba(255,255,255,.08)}.links a:hover,.chip:hover{border-color:var(--mint);color:var(--mint)}.hero{display:grid;grid-template-columns:minmax(0,1.05fr) minmax(360px,.95fr);gap:34px;align-items:center;padding:72px 0 42px}.eyebrow{color:var(--gold);text-transform:uppercase;font-weight:1000;letter-spacing:.48em;font-size:12px}.hero h1{font-size:clamp(56px,8vw,116px);line-height:.82;margin:20px 0 18px;letter-spacing:-.085em}.grad{font-family:Georgia,serif;font-style:italic;background:linear-gradient(100deg,var(--gold),var(--mint),var(--aqua),var(--violet));-webkit-background-clip:text;background-clip:text;color:transparent}.hero p{font-size:clamp(19px,2.2vw,28px);line-height:1.22;font-weight:830;color:#eef8ff;max-width:850px}.boundary{margin-top:22px;border:1px solid rgba(255,107,154,.52);background:rgba(85,19,46,.34);border-radius:18px;padding:15px 18px;color:#fff;font-weight:850}.hero-cta{display:flex;gap:12px;flex-wrap:wrap;margin-top:24px}.btn{border:none;cursor:pointer;display:inline-flex;align-items:center;gap:8px}.btn.primary{background:linear-gradient(120deg,var(--gold),var(--mint));color:#061015;box-shadow:0 12px 40px rgba(114,255,209,.25);font-weight:1000}.btn.secondary{background:rgba(255,255,255,.1)}.console-card{position:relative;min-height:610px;border:1px solid var(--line);border-radius:34px;background:linear-gradient(150deg,rgba(25,39,61,.88),rgba(13,18,32,.86));box-shadow:var(--shadow);overflow:hidden;padding:22px}.console-card:before{content:"";position:absolute;inset:-25%;background:conic-gradient(from 180deg,transparent,rgba(114,255,209,.22),transparent,rgba(255,231,109,.18),transparent);filter:blur(28px);animation:spin 14s linear infinite;opacity:.65}@keyframes spin{to{transform:rotate(360deg)}}.console-inner{position:relative;z-index:1}.console-top{display:flex;justify-content:space-between;align-items:center;gap:10px;margin-bottom:14px}.pill{display:inline-flex;align-items:center;gap:8px;border:1px solid rgba(114,255,209,.25);background:rgba(0,0,0,.24);border-radius:999px;padding:8px 12px;color:var(--mint);font-weight:1000;font-size:12px}.pulse{width:9px;height:9px;background:var(--mint);border-radius:999px;box-shadow:0 0 20px var(--mint)}.objective-box{background:rgba(3,8,16,.72);border:1px solid var(--line);border-radius:24px;padding:18px}.objective-box label{display:block;color:var(--gold);font-size:12px;letter-spacing:.28em;text-transform:uppercase;font-weight:1000;margin-bottom:10px}.objective-box textarea{width:100%;min-height:150px;resize:vertical;border:1px solid rgba(255,255,255,.14);border-radius:18px;background:rgba(255,255,255,.07);color:var(--text);padding:16px;font:700 18px/1.35 ui-sans-serif,system-ui;outline:none}.objective-box textarea:focus{border-color:var(--mint);box-shadow:0 0 0 4px rgba(114,255,209,.12)}.examples{display:flex;flex-wrap:wrap;gap:8px;margin-top:12px}.mini{border:1px solid rgba(255,255,255,.16);background:rgba(255,255,255,.06);border-radius:999px;padding:8px 10px;color:#e7f1ff;cursor:pointer;font-weight:800;font-size:12px}.mini:hover{color:var(--mint);border-color:var(--mint)}.action-row{display:flex;gap:10px;flex-wrap:wrap;margin-top:14px}.metrics{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin:16px 0}.metric{border:1px solid rgba(255,255,255,.12);border-radius:18px;background:rgba(255,255,255,.07);padding:13px}.metric b{font-size:25px}.metric span{display:block;color:var(--gold);font-weight:950;font-size:11px;text-transform:uppercase;letter-spacing:.18em}.pipeline{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin:12px 0}.step{border:1px solid rgba(255,255,255,.12);border-radius:14px;padding:10px;background:rgba(255,255,255,.06);font-weight:900;color:#d8e7f5}.step.on{border-color:var(--mint);color:var(--mint);box-shadow:0 0 28px rgba(114,255,209,.12)}.log{min-height:118px;border:1px solid rgba(114,255,209,.22);background:#02070d;border-radius:18px;padding:13px;font:800 13px/1.45 ui-monospace,SFMono-Regular,Menlo,monospace;color:var(--mint);white-space:pre-wrap;overflow:auto}.section{padding:34px 0}.section h2{font-size:clamp(38px,5vw,72px);line-height:.92;letter-spacing:-.06em;margin:0 0 12px}.cards{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}.card,.artifact,.route-card{border:1px solid rgba(255,255,255,.14);border-radius:24px;background:linear-gradient(150deg,rgba(255,255,255,.1),rgba(255,255,255,.05));padding:20px;box-shadow:0 18px 50px rgba(0,0,0,.2)}.card h3,.artifact h3,.route-card h3{font-size:24px;line-height:1.02;margin:0 0 9px}.card p,.artifact p,.route-card p{color:var(--muted);font-weight:650;line-height:1.5}.grid2{display:grid;grid-template-columns:1fr 1fr;gap:18px}.artifact pre{white-space:pre-wrap;word-break:break-word;background:#030911;border:1px solid rgba(114,255,209,.18);border-radius:16px;padding:14px;color:#c8fff0;max-height:360px;overflow:auto}.routes{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.route-card a{display:inline-flex;margin-top:10px;color:var(--mint);font-weight:950}.footer{padding:56px 0 80px;color:#c7d3df}.float{position:fixed;right:18px;bottom:18px;z-index:80;display:flex;gap:8px}.float a{padding:13px 16px;border-radius:999px;background:linear-gradient(120deg,var(--gold),var(--mint));color:#061015;text-decoration:none;font-weight:1000;box-shadow:0 16px 40px rgba(0,0,0,.3)}.toast{position:fixed;left:50%;bottom:24px;transform:translateX(-50%);background:#051015;border:1px solid var(--line);color:var(--mint);padding:12px 16px;border-radius:999px;z-index:120;display:none}.toast.show{display:block}.mode-tabs{display:flex;flex-wrap:wrap;gap:8px;margin:12px 0}.mode-tabs button{border:1px solid rgba(255,255,255,.16);background:rgba(255,255,255,.07);color:var(--text);border-radius:999px;padding:9px 11px;font-weight:900;cursor:pointer}.mode-tabs button.active{background:linear-gradient(120deg,var(--gold),var(--mint));color:#061015;border-color:transparent}.state-badge{font-size:22px;font-weight:1000;color:var(--gold);overflow-wrap:anywhere}.warning{border-color:rgba(255,107,154,.44);background:rgba(255,107,154,.12)}\n@media(max-width:960px){.hero{grid-template-columns:1fr}.console-card{min-height:auto}.cards,.grid2,.routes{grid-template-columns:1fr}.metrics,.pipeline{grid-template-columns:repeat(2,1fr)}.nav{align-items:flex-start;flex-direction:column}.links{justify-content:flex-start}.hero h1{font-size:60px}}\n'
