JS='\n(function(){const routes=(window.GOALOS_V21_ROUTE_INDEX||[]).slice();const fallback=[{title:\'Start Here\',url:\'start-here.html\',category:\'Start\',description:\'Start in 60 seconds.\'},{title:\'Mainnet Contract Atlas\',url:\'mainnet-contract-atlas.html\',category:\'Mainnet\',description:\'Explore the 48 GoalOS-created Ethereum Mainnet contracts.\'},{title:\'Proof Run 001\',url:\'proof-run-001-docket.html\',category:\'Evidence\',description:\'Review the repository-readiness Evidence Docket.\'},{title:\'Loop to RSI State-Capacity\',url:\'from-loop-to-rsi-state-capacity.html\',category:\'Loop to RSI\',description:\'Understand deterministic RSI governance.\'},{title:\'Trust Boundary\',url:\'trust-boundary.html\',category:\'Trust\',description:\'No user data, no user funds, no wallet, no transaction.\'},{title:\'Token Boundary\',url:\'token-boundary.html\',category:\'Token\',description:\'AGIALPHA public contract identification only.\'}];const all=routes.length?routes:fallback;const $=id=>document.getElementById(id);const objective=$(\'goalos-v21-objective\'),log=$(\'goalos-v21-log\'),state=$(\'goalos-v21-state\'),score=$(\'goalos-v21-score\'),routeCount=$(\'goalos-v21-route-count\'),risk=$(\'goalos-v21-risk\'),contract=$(\'goalos-v21-contract\'),claims=$(\'goalos-v21-claims\'),routeBox=$(\'goalos-v21-routes\'),packageBox=$(\'goalos-v21-package\'),nextBtn=$(\'goalos-v21-open-next\');let current=null;const intents=[{id:\'mainnet_contracts\',label:\'48 Mainnet contracts\',keys:[\'48\',\'contract\',\'contracts\',\'mainnet\',\'etherscan\',\'chain\',\'chainid\',\'proof rail\',\'atlas\'],targets:[\'mainnet-contract-atlas.html\',\'mainnet-proof-rail.html\',\'contract-academy.html\']},{id:\'start\',label:\'Start / onboarding\',keys:[\'start\',\'begin\',\'new\',\'learn\',\'explain\',\'onboard\',\'non technical\',\'where do i start\'],targets:[\'start-here.html\',\'pathfinder.html\',\'demo-ecosystem-registry.html\']},{id:\'proof_run\',label:\'Proof Run / Evidence Docket\',keys:[\'proof run\',\'proofrun\',\'docket\',\'evidence\',\'review\',\'validator\',\'claims matrix\',\'replay\'],targets:[\'proof-run-001-docket.html\',\'reviewer-room.html\',\'evidence-docket-theatre.html\']},{id:\'loop_rsi\',label:\'Loop to RSI\',keys:[\'loop\',\'rsi\',\'recursive\',\'invention\',\'move-37\',\'omni\',\'baseline\',\'state capacity\'],targets:[\'from-loop-to-rsi-state-capacity.html\',\'from-loop-to-rsi-sovereign-console.html\',\'loop-bottleneck-observatory.html\']},{id:\'token\',label:\'Token boundary\',keys:[\'token\',\'agialpha\',\'$agialpha\',\'wallet\',\'buy\',\'sell\',\'exchange\',\'liquidity\',\'custody\'],targets:[\'token-boundary.html\',\'trust-boundary.html\',\'no-data-no-funds.html\']},{id:\'privacy\',label:\'Privacy / data boundary\',keys:[\'privacy\',\'data\',\'gdpr\',\'personal\',\'customer\',\'secret\',\'credential\',\'private key\',\'seed phrase\'],targets:[\'trust-boundary.html\',\'privacy.html\',\'data-boundary.html\',\'no-data-no-funds.html\']},{id:\'mission\',label:\'Mission / proof path\',keys:[\'mission\',\'objective\',\'want\',\'need\',\'goal\',\'plan\',\'action\',\'decision\',\'capability\'],targets:[\'mission-command-center.html\',\'objective-command-center.html\',\'proof-to-action-command-room.html\',\'pathfinder.html\']},{id:\'registry\',label:\'Registry / all pages\',keys:[\'all pages\',\'site map\',\'registry\',\'demo\',\'demos\',\'where everything\',\'find\'],targets:[\'site-map.html\',\'demo-ecosystem-registry.html\',\'search.html\']}];function norm(s){return(s||\'\').toLowerCase().replace(/[^a-z0-9$\\-\\s]/g,\' \').replace(/\\s+/g,\' \').trim()}function words(s){return new Set(norm(s).split(\' \').filter(Boolean))}function hash(s){let h=2166136261;for(let i=0;i<s.length;i++){h^=s.charCodeAt(i);h=Math.imul(h,16777619)}return(\'00000000\'+(h>>>0).toString(16)).slice(-8)}function includesAny(t,arr){return arr.some(k=>t.includes(k))}function scoreRoute(q,r){const qw=words(q),blob=norm([r.title,r.category,r.description,r.url].join(\' \'));let s=0;qw.forEach(w=>{if(w.length>2&&blob.includes(w))s+=2});if(blob.includes(\'mainnet\')&&q.includes(\'contract\'))s+=12;if(blob.includes(\'rsi\')&&q.includes(\'rsi\'))s+=12;if(blob.includes(\'proof\')&&q.includes(\'proof\'))s+=8;if(blob.includes(\'token\')&&q.includes(\'token\'))s+=10;if(blob.includes(\'trust\')&&q.includes(\'data\'))s+=10;return s}function uniqueByUrl(list){const seen=new Set();return list.filter(r=>{if(!r||!r.url||seen.has(r.url))return false;seen.add(r.url);return true})}function getRoute(url){return all.find(r=>r.url===url)||fallback.find(r=>r.url===url)||{title:url.replace(\'.html\',\'\'),url,category:\'GoalOS\',description:\'GoalOS route\'}}function analyze(input){const q=norm(input),id=\'GOALOS-MISSION-\'+hash(q).toUpperCase();const matched=intents.map(i=>({intent:i,score:i.keys.reduce((n,k)=>n+(q.includes(k)?1:0),0)})).filter(x=>x.score>0).sort((a,b)=>b.score-a.score);const primary=(matched[0]&&matched[0].intent)||intents[6];const sensitive=includesAny(q,[\'private key\',\'seed phrase\',\'password\',\'credential\',\'customer data\',\'personal data\',\'confidential\',\'secret\']);const production=includesAny(q,[\'send funds\',\'buy token\',\'sell token\',\'trade\',\'swap\',\'bridge\',\'deploy production\',\'mainnet transaction\',\'make transaction\',\'custody\']);const routeTargets=uniqueByUrl([...(primary.targets||[]).map(getRoute),...all.map(r=>Object.assign({},r,{_score:scoreRoute(q,r)})).filter(r=>r._score>0).sort((a,b)=>(b._score||0)-(a._score||0)).slice(0,7)]).slice(0,6);const decision=sensitive?\'BLOCK_PRIVATE_DATA_BOUNDARY\':production?\'HOLD_HUMAN_REVIEW_REQUIRED\':routeTargets.length?\'MISSION_REVIEW_READY\':\'HOLD_ROUTE_SELECTION_REQUIRED\';const readiness=decision===\'MISSION_REVIEW_READY\'?94:decision===\'HOLD_HUMAN_REVIEW_REQUIRED\'?72:58;const contractObj={mission_id:id,version:\'goalos-universal-mission-autopilot-v21\',objective:input.trim(),intent:primary.label,risk_class:sensitive?\'HIGH_BOUNDARY\':production?\'HIGH_AUTHORITY\':\'PUBLIC_SAFE\',decision_state:decision,success_criteria:[\'Objective is bounded in public-safe terms\',\'Relevant GoalOS routes are selected\',\'Required evidence is listed\',\'Human review boundary is preserved\'],hard_boundaries:[\'No user data\',\'No user funds\',\'No wallet\',\'No transaction\',\'No network call\',\'No production authority\',\'Human review required\'],recommended_routes:routeTargets.map(r=>({title:r.title,url:r.url,category:r.category})),required_artifacts:[\'Mission Contract\',\'Claims Matrix\',\'Evidence Docket Plan\',\'Action Graph\',\'Reviewer Brief\',\'Chronicle Stub\',\'Capability Package Stub\'],next_best_route:(routeTargets[0]&&routeTargets[0].url)||\'pathfinder.html\'};const claimRows=[{claim:\'What the user wants\',evidence:\'Plain-language objective preserved as public-safe mission text\',gate:\'Boundary check\'},{claim:\'Where to go next\',evidence:\'Route scoring across public site index and curated GoalOS intents\',gate:\'Route integrity\'},{claim:\'What proof is needed\',evidence:\'Claims matrix + Evidence Docket plan + reviewer brief\',gate:\'Evidence completeness\'},{claim:\'What is not authorized\',evidence:\'No data, funds, wallet, transaction, network call, or production authority\',gate:\'Human review\'}];const actionGraph=[[\'01\',\'Objective\',\'Capture user intent without collecting sensitive data\'],[\'02\',\'Bound\',\'Apply no-data/no-funds/no-wallet boundary\'],[\'03\',\'Route\',\'Select best GoalOS public proof surface\'],[\'04\',\'Contract\',\'Generate mission contract JSON\'],[\'05\',\'Docket\',\'Create evidence docket plan\'],[\'06\',\'Review\',\'Prepare reviewer brief and next page\'],[\'07\',\'Capability\',\'Package reusable mission stub\']];return{id,primary,matched,decision,readiness,risk:contractObj.risk_class,routes:routeTargets,contractObj,claimRows,actionGraph}}function esc(s){return String(s||\'\').replace(/[&<>"]/g,m=>({\'&\':\'&amp;\',\'<\':\'&lt;\',\'>\':\'&gt;\',\'"\':\'&quot;\'}[m]))}function makePackage(r){return \'# GoalOS Mission Package\\n\\nMission ID: \'+r.id+\'\\nDecision: \'+r.decision+\'\\nIntent: \'+r.primary.label+\'\\n\\n## Objective\\n\'+r.contractObj.objective+\'\\n\\n## Next best route\\n\'+r.contractObj.next_best_route+\'\\n\\n## Action Graph\\n\'+r.actionGraph.map(x=>x.join(\' | \')).join(\'\\n\')+\'\\n\\n## Boundaries\\n- \'+r.contractObj.hard_boundaries.join(\'\\n- \')+\'\\n\\n## Mission Contract JSON\\n```json\\n\'+JSON.stringify(r.contractObj,null,2)+\'\\n```\\n\'}function render(result){current=result;state.textContent=result.decision;score.textContent=result.readiness+\'%\';routeCount.textContent=String(result.routes.length);risk.textContent=result.risk.replace(/_/g,\' \');document.querySelectorAll(\'.step\').forEach((el,i)=>el.classList.toggle(\'on\',i<=(result.decision===\'MISSION_REVIEW_READY\'?7:4)));log.textContent=[\'01 Objective received.\',\'02 Boundary applied: no data, no funds, no wallet, no transaction.\',\'03 Intent: \'+result.primary.label+\'.\',\'04 Routes selected: \'+result.routes.map(r=>r.title).join(\' · \')+\'.\',\'05 Decision: \'+result.decision+\'.\'].join(\'\\n\');contract.textContent=JSON.stringify(result.contractObj,null,2);claims.innerHTML=result.claimRows.map(r=>\'<div class="card"><h3>\'+esc(r.claim)+\'</h3><p><b>Evidence:</b> \'+esc(r.evidence)+\'</p><p><b>Gate:</b> \'+esc(r.gate)+\'</p></div>\').join(\'\');routeBox.innerHTML=result.routes.map((r,idx)=>\'<div class="route-card"><div class="eyebrow">Route \'+String(idx+1).padStart(2,\'0\')+\' · \'+esc(r.category||\'GoalOS\')+\'</div><h3>\'+esc(r.title||r.url)+\'</h3><p>\'+esc(r.description||\'Open this GoalOS surface next.\')+\'</p><a href="\'+esc(r.url)+\'">Open route →</a></div>\').join(\'\')||\'<div class="route-card warning"><h3>No route selected yet</h3><p>Try a clearer objective or open Pathfinder.</p><a href="pathfinder.html">Open Pathfinder →</a></div>\';packageBox.textContent=makePackage(result);if(nextBtn)nextBtn.disabled=!result.contractObj.next_best_route}function download(name,text,type){const a=document.createElement(\'a\'),blob=new Blob([text],{type:type||\'text/plain\'});a.href=URL.createObjectURL(blob);a.download=name;document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove()},150)}function run(){render(analyze((objective&&objective.value)||\'I want to understand GoalOS and choose the right proof path.\'))}document.addEventListener(\'DOMContentLoaded\',function(){if($(\'goalos-v21-route-total\'))$(\'goalos-v21-route-total\').textContent=String(all.length);document.querySelectorAll(\'[data-v21-example]\').forEach(b=>b.addEventListener(\'click\',()=>{objective.value=b.getAttribute(\'data-v21-example\');run()}));$(\'goalos-v21-generate\').addEventListener(\'click\',run);$(\'goalos-v21-simulate\').addEventListener(\'click\',()=>{run();if(current){log.textContent+=\'\\n06 Mission OS cycle simulated locally.\\n07 Review-ready package assembled.\'}});if(nextBtn)nextBtn.addEventListener(\'click\',()=>{if(!current)run();if(current&&current.contractObj.next_best_route)window.location.href=current.contractObj.next_best_route});$(\'goalos-v21-download\').addEventListener(\'click\',()=>{if(!current)run();download(\'goalos-mission-package-\'+current.id+\'.md\',makePackage(current),\'text/markdown\')});$(\'goalos-v21-download-json\').addEventListener(\'click\',()=>{if(!current)run();download(\'goalos-mission-contract-\'+current.id+\'.json\',JSON.stringify(current.contractObj,null,2),\'application/json\')});$(\'goalos-v21-copy\').addEventListener(\'click\',()=>{if(!current)run();const ta=document.createElement(\'textarea\');ta.value=makePackage(current);document.body.appendChild(ta);ta.select();document.execCommand(\'copy\');ta.remove();const t=$(\'goalos-v21-toast\');if(t){t.classList.add(\'show\');setTimeout(()=>t.classList.remove(\'show\'),1800)}});document.querySelectorAll(\'.mode-tabs button\').forEach(btn=>btn.addEventListener(\'click\',()=>{document.querySelectorAll(\'.mode-tabs button\').forEach(b=>b.classList.remove(\'active\'));btn.classList.add(\'active\');if(!current)run();log.textContent+=\'\\nMode selected: \'+btn.textContent.trim()+\'.\'}));document.addEventListener(\'keydown\',e=>{if(e.key===\'/\'&&document.activeElement!==objective){e.preventDefault();objective.focus()}});run()})})();\n'
