TITLE_RE=re.compile(r'<title[^>]*>(.*?)</title>',re.I|re.S); H1_RE=re.compile(r'<h1[^>]*>(.*?)</h1>',re.I|re.S); DESC_RE=re.compile(r'<meta[^>]+name=["\']description["\'][^>]+content=["\'](.*?)["\']',re.I|re.S)
def clean(s): return re.sub(r'\s+',' ',re.sub('<[^>]+>',' ',s or '')).strip()
def category_for(name,title):
    blob=(name+' '+title).lower()
    if any(k in blob for k in ['rsi','loop','bottleneck','flight','move37']): return 'Loop to RSI'
    if any(k in blob for k in ['mainnet','contract','ethereum','proof rail','academy']): return 'Mainnet Contracts'
    if any(k in blob for k in ['proof','docket','evidence','validator','reviewer','ledger']): return 'Evidence & Review'
    if any(k in blob for k in ['trust','token','privacy','data','boundary','security','disclaimer']): return 'Trust & Boundary'
    if any(k in blob for k in ['start','pathfinder','site-map','search','registry','docs','health','website']): return 'Navigation & Docs'
    if any(k in blob for k in ['mission','objective','autopilot','command']): return 'Mission OS'
    if any(k in blob for k in ['capability','economy','value','settlement','market']): return 'Capability & Economy'
    return 'Additional'
def write(path,text): path.parent.mkdir(parents=True,exist_ok=True); path.write_text(text,encoding='utf-8')
def inventory():
    PUBLIC.mkdir(exist_ok=True); ASSETS.mkdir(parents=True,exist_ok=True); out=[]
    for p in sorted(PUBLIC.glob('*.html')):
        text=p.read_text(encoding='utf-8',errors='ignore')
        title=clean((TITLE_RE.search(text) or H1_RE.search(text) or [None,''])[1]) or p.stem.replace('-',' ').title()
        desc=clean((DESC_RE.search(text) or [None,''])[1]) or f'Open {title} as part of the GoalOS public proof surface.'
        out.append({'title':title[:120],'url':p.name,'category':category_for(p.name,title),'description':desc[:220]})
    for title,url,cat,desc in [('Tell GoalOS — Universal Mission Autopilot','tell-goalos.html','Mission OS','Enter a plain-language objective and generate a public-safe Mission Contract, Evidence Docket plan, Action Graph, and next route.'),('Universal Mission Autopilot','universal-mission-autopilot.html','Mission OS','Alias for the GoalOS one-box mission autopilot.'),('Mainnet Contract Atlas','mainnet-contract-atlas.html','Mainnet Contracts','Explore the 48 GoalOS-created Ethereum Mainnet contracts.'),('Proof Run 001 Docket','proof-run-001-docket.html','Evidence & Review','Review the public repository-readiness Evidence Docket.'),('Trust Boundary','trust-boundary.html','Trust & Boundary','No data, no funds, no wallet, no transaction, no production authority.'),('Token Boundary','token-boundary.html','Trust & Boundary','AGIALPHA public contract identification only; not available from GoalOS.')]:
        if not any(r['url']==url for r in out): out.append({'title':title,'url':url,'category':cat,'description':desc})
    return out
def inject_float(text):
    if 'goalos-v21-float' not in text:
        if '</head>' in text and 'goalos-autopilot-float-v21.css' not in text: text=text.replace('</head>','<link rel="stylesheet" href="assets/goalos-autopilot-float-v21.css">\n</head>')
        anchor='<a class="goalos-v21-float" href="tell-goalos.html" aria-label="Tell GoalOS what you want">Tell GoalOS</a>'
        text=text.replace('</body>',anchor+'\n</body>') if '</body>' in text else text+anchor
    return text
def patch_all_pages():
    for p in PUBLIC.glob('*.html'):
        if p.name in {CANONICAL,ALIAS}: continue
        text=p.read_text(encoding='utf-8',errors='ignore'); new=inject_float(text)
        if new!=text: p.write_text(new,encoding='utf-8')
